import{_ as a,O as e,H as i,f as n,k as s,i as r}from"./chunks/framework.Pt2pSV98.js";const m=JSON.parse('{"title":"AI Skills（技能）","description":"AI Agent 的可复用模块化能力，让 LLM 具备特定领域的专业技能","frontmatter":{"title":"AI Skills（技能）","description":"AI Agent 的可复用模块化能力，让 LLM 具备特定领域的专业技能","difficulty":"intermediate"},"headers":[],"relativePath":"terms/ai-skills.md","filePath":"terms/ai-skills.md"}'),o={name:"terms/ai-skills.md"};function d(h,t,p,c,g,u){const l=e("DifficultyBadge");return i(),n("div",null,[s(l,{level:"intermediate"}),t[0]||(t[0]=r(`<h1 id="ai-skills-技能" tabindex="-1">AI Skills（技能） <a class="header-anchor" href="#ai-skills-技能" aria-label="Permalink to &quot;AI Skills（技能）&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p><strong>AI Skills</strong> 是赋予 AI Agent 的<strong>模块化可复用能力</strong>——就像给一个全能助手装上&quot;专业技能包&quot;，让它不需要从零摸索就能完成特定领域的任务。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>假设你请了一个万能助理（LLM），他什么都会一点但什么都不精。<strong>Skills</strong> 就是给他装的&quot;专业模块&quot;：</p><ul><li>装一个「Excel 处理 Skill」→ 他立刻能处理复杂表格</li><li>装一个「代码审查 Skill」→ 他立刻能按团队规范审查代码</li><li>装一个「数据分析 Skill」→ 他立刻能输出专业分析报告</li></ul><p>每个 Skill 就像手机上的 App——即装即用，按需组合。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>AI Skills 是一组<strong>预设的指令、工具、知识库和约束条件的集合</strong>，通常包含：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skill = System Prompt（角色定义）</span></span>
<span class="line"><span>      + Tools（可用工具/API）</span></span>
<span class="line"><span>      + Knowledge（知识库/RAG 上下文）</span></span>
<span class="line"><span>      + Constraints（输出约束/规则）</span></span></code></pre></div><p>当一个 Agent 被赋予某个 Skill 时，它会自动加载对应的系统提示词、工具集和行为规范，从而在特定任务上表现出专业水准。</p><h3 id="与-function-calling-的区别" tabindex="-1">与 Function Calling 的区别 <a class="header-anchor" href="#与-function-calling-的区别" aria-label="Permalink to &quot;与 Function Calling 的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Function Calling</th><th>AI Skills</th></tr></thead><tbody><tr><td>粒度</td><td>单个函数调用</td><td>一整套能力</td></tr><tr><td>范围</td><td>执行具体操作</td><td>定义角色+工具+行为</td></tr><tr><td>组合</td><td>独立</td><td>可叠加组合</td></tr><tr><td>复用</td><td>需重复声明</td><td>一次定义随处使用</td></tr></tbody></table><h2 id="常见应用场景" tabindex="-1">常见应用场景 <a class="header-anchor" href="#常见应用场景" aria-label="Permalink to &quot;常见应用场景&quot;">​</a></h2><ul><li><strong>编程助手 Skill</strong>：携带代码规范、项目上下文、调试工具链</li><li><strong>写作 Skill</strong>：预设风格指南、术语库、审核规则</li><li><strong>数据分析 Skill</strong>：绑定 SQL 查询、可视化工具、报表模板</li><li><strong>客服 Skill</strong>：配置知识库、话术模板、升级流程</li></ul><h2 id="代表实践" tabindex="-1">代表实践 <a class="header-anchor" href="#代表实践" aria-label="Permalink to &quot;代表实践&quot;">​</a></h2><ul><li><strong>OpenCode / Cline</strong>：通过 <code>.clinerules</code> 或 Skill 文件定义 Agent 行为</li><li><strong>GPTs</strong>（OpenAI）：通过指令+知识+动作自定义 ChatGPT 行为</li><li><strong>Custom Instructions</strong>（Claude）：项目级自定义指令</li><li><strong>Agent 框架</strong>：LangChain、CrewAI 中的 Tool + Prompt 组合模式</li></ul><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/agent.html">Agent</a> — Skills 是 Agent 的能力来源</li><li><a href="/ai-knowledge/terms/function-calling.html">Function Calling</a> — Skills 底层的工具调用机制</li><li><a href="/ai-knowledge/prompts/system-prompt.html">System Prompt</a> — Skills 的一部分</li><li><a href="/ai-knowledge/terms/rag.html">RAG</a> — Skills 的知识来源方式</li><li><a href="/ai-knowledge/terms/mcp.html">MCP</a> — Skills 的标准协议层</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>Skills = 给 Agent 安装专业技能包。好比你的手机装 App——装一个「修图 App」它就会修图，装一个「写代码 App」它就会写代码。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://github.com/opencode-ai" target="_blank" rel="noreferrer">OpenCode Skills</a> 开源 Agent 技能框架</li><li><a href="https://chatgpt.com/gpts" target="_blank" rel="noreferrer">OpenAI GPTs</a> 官方自定义 GPT</li><li>Anthropic Claude 项目自定义指令</li></ul>`,23))])}const f=a(o,[["render",d]]);export{m as __pageData,f as default};
